using Abbey.CameraRig;
using Abbey.Core;
using Abbey.Light;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Abbey.EditorTools
{
    /// <summary>
    /// Builds the Prototype 0.1 greybox scene entirely from code (AGENTS.md: scenes
    /// are generated by editor bootstrap code, never the source of truth for logic).
    /// Greybox only — real assets come from the Blender pipeline later.
    /// </summary>
    public static class PrototypeSceneBuilder
    {
        [MenuItem("Tools/Abbey/Build Prototype Scene")]
        public static void BuildPrototypeScene()
        {
            var scene = EditorSceneManager.NewScene(NewSceneSetup.EmptyScene, NewSceneMode.Single);
            PopulateScene();
            Debug.Log("[Abbey] Prototype greybox scene built. Save it manually if you want to keep it; " +
                      "logic never depends on a saved scene file.");
            SceneManager.SetActiveScene(scene);
        }

        /// <summary>Creates the greybox world objects in the active scene.</summary>
        public static void PopulateScene()
        {
            var config = PrototypeConfig.LoadOrDefault();

            // Ground plane: coastal meadow placeholder, 100x100 units.
            var ground = GameObject.CreatePrimitive(PrimitiveType.Plane);
            ground.name = "Ground";
            ground.transform.localScale = new Vector3(10f, 1f, 10f);

            // Fixed sun matching the camera-relative light rule in ART_BIBLE.md.
            var sunGO = new GameObject("Sun");
            var sun = sunGO.AddComponent<UnityEngine.Light>();
            sun.type = LightType.Directional;
            sunGO.transform.rotation = Quaternion.Euler(50f, IsoCameraController.Yaw - 30f, 0f);

            // Simulation core.
            var clockGO = new GameObject("GameClock");
            clockGO.AddComponent<GameClock>();

            // Camera rig.
            var camGO = new GameObject("IsoCamera");
            camGO.tag = "MainCamera";
            camGO.AddComponent<Camera>();
            var rig = camGO.AddComponent<IsoCameraController>();
            rig.SetWorldBounds(new Vector2(-50f, -50f), new Vector2(50f, 50f));

            // Campfire greybox: a cylinder with a LightSource territory.
            var campfire = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
            campfire.name = "Campfire";
            campfire.transform.position = Vector3.zero;
            campfire.transform.localScale = new Vector3(0.8f, 0.25f, 0.8f);
            var fireLight = campfire.AddComponent<LightSource>();
            fireLight.radius = config.campfireRadius;
            fireLight.strength = config.campfireStrength;
            fireLight.fuelSeconds = config.defaultFuelSeconds;
            fireLight.fuelConsumptionPerSecond = config.fuelConsumptionPerSecond;

            // Lantern post greybox near the meadow edge.
            var lantern = GameObject.CreatePrimitive(PrimitiveType.Cube);
            lantern.name = "LanternPost";
            lantern.transform.position = new Vector3(10f, 0.5f, 6f);
            lantern.transform.localScale = new Vector3(0.3f, 2f, 0.3f);
            var lanternLight = lantern.AddComponent<LightSource>();
            lanternLight.radius = config.lanternRadius;
            lanternLight.strength = config.lanternStrength;
            lanternLight.fuelSeconds = config.defaultFuelSeconds;
            lanternLight.fuelConsumptionPerSecond = config.fuelConsumptionPerSecond;
        }
    }
}
